class FacebookCustomTabLoginActivity : ComponentActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (savedInstanceState == null) {
            val appId = intent.getStringExtra(EXTRA_APP_ID) ?: ""
            val redirectUri = intent.getStringExtra(EXTRA_REDIRECT_URI) ?: ""
            val state = intent.getStringExtra(EXTRA_STATE) ?: ""
            val scopes = intent.getStringArrayExtra(EXTRA_SCOPES) ?: emptyArray()

            val authUri = Uri.Builder()
                .scheme("https")
                .authority("www.facebook.com")
                .appendPath("v19.0")
                .appendPath("dialog")
                .appendPath("oauth")
                .appendQueryParameter("client_id", appId)
                .appendQueryParameter("redirect_uri", redirectUri)
                .appendQueryParameter("state", state)
                .appendQueryParameter("response_type", "token")
                .appendQueryParameter("display", "touch")
                .appendQueryParameter("scope", scopes.joinToString(","))
                .build()

            val customTabsIntent = androidx.browser.customtabs.CustomTabsIntent.Builder().build()
            customTabsIntent.intent.addFlags(Intent.FLAG_ACTIVITY_NO_HISTORY)
            customTabsIntent.launchUrl(this, authUri)
        }
    }

    override fun onNewIntent(intent: Intent) {
