            } else {
                putExtra(EXTRA_RESULT_ACCESS_TOKEN, accessToken)
                putExtra(EXTRA_RESULT_USER_ID, userId)
                putExtra(EXTRA_RESULT_EXPIRES_AT, System.currentTimeMillis() + (expiresIn * 1000L))
            }
        }

        setResult(Activity.RESULT_OK, resultIntent)
        finish()
    }

    private fun getStringExtraOrNull(key: String): String? = try {
