    private fun parseUrlFragment(fragment: String): Map<String, String> {
        if (fragment.isBlank()) return emptyMap()
        return fragment.split("&")
            .mapNotNull { part ->
                val idx = part.indexOf("=")
                if (idx <= 0) null else {
